urlSummarizer.js.content:
const log = {
  info:  (...a) => console.log(...a),
  warn:  (...a) => console.warn(...a),
  error: (...a) => console.error(...a),
};

import { cfg } from "../lib/config.js";
import { safeErr } from "../lib/errors.js";

import { fetchPageHtml, extractReadableText } from "../services/webPage.js";
import { summarizeDocument } from "../services/summarizer.js";
import { extractUrls, hostnameOf, isXUrl } from "../services/urlTools.js";
import { fetchXContent } from "../services/xGateway.js";

const chatLocks = new Set();
let globalInFlight = 0;

function chatKey(ctx) {
  return String(ctx.chat?.id || ctx.from?.id || "unknown");
}

function globalCap() {
  const configured = Number(cfg.CONCURRENCY || 20);
  if (!Number.isFinite(configured) || configured <= 0) return 1;
  return Math.max(1, Math.min(configured, 2));
}

function shouldHandleGroupMessage(ctx, text) {
  const chatType = ctx.chat?.type || "private";
  if (chatType === "private") return { ok: true, text };

  const botUsername = ctx.me?.username || ctx.botInfo?.username || "";
  const replyTo = ctx.message?.reply_to_message;
  const isReplyToBot = Boolean(replyTo?.from?.is_bot && botUsername && replyTo.from.username?.toLowerCase() === botUsername.toLowerCase());
  const mention = botUsername ? `@${botUsername}` : "";
  const isMentioned = mention ? text.toLowerCase().includes(mention.toLowerCase()) : false;

  if (!isMentioned && !isReplyToBot) return { ok: false, text };

  const cleaned = mention ? text.replace(new RegExp(`${mention}\\b`, "ig"), "").trim() : text;
  return { ok: true, text: cleaned };
}

async function summarizeUrl(ctx, url) {
  await ctx.api.sendChatAction(ctx.chat.id, "typing");
  await ctx.reply(`Processing ${hostnameOf(url)}...`);

  let document;

  if (isXUrl(url)) {
    const xResult = await fetchXContent(url);

    if (!xResult.ok && !xResult.configured) {
      await ctx.reply("X/Twitter summarization is not configured. Set COOKMYBOTS_X_ENDPOINT and COOKMYBOTS_X_KEY, then connect an X account in CookMyBots.");
      return;
    }

    if (!xResult.ok) {
      await ctx.reply("I could not retrieve that tweet or thread. It may be private, deleted, rate-limited, or inaccessible.");
      return;
    }

    document = xResult.document;
  } else {
    const page = await fetchPageHtml(url);
    document = extractReadableText(page);
  }

  await ctx.api.sendChatAction(ctx.chat.id, "typing");
  const summary = await summarizeDocument(document);

  if (!summary.ok) {
    log.warn("[summary] failure", { host: hostnameOf(url), error: String(summary.error || "unknown").slice(0, 300) });
    await ctx.reply("I could not summarize this link right now. Please try again later.");
    return;
  }

  await ctx.reply(summary.content);
}

export function registerUrlSummarizer(bot) {
  bot.on("message:text", async (ctx, next) => {
    const raw = ctx.message?.text || "";
    if (raw.startsWith("/")) return next();

    const groupDecision = shouldHandleGroupMessage(ctx, raw);
    if (!groupDecision.ok) return next();

    const urls = extractUrls(groupDecision.text);
    log.info("[url] detection", {
      chatId: String(ctx.chat?.id || ""),
      count: urls.length,
      hosts: urls.map(hostnameOf)
    });

    if (urls.length === 0) {
      await ctx.reply("Send me a webpage, x.com, or twitter.com link and I will summarize it in 3 sentences.");
      return;
    }

    const key = chatKey(ctx);
    if (chatLocks.has(key)) {
      await ctx.reply("I’m working on your last request. Please wait a moment.");
      return;
    }

    if (globalInFlight >= globalCap()) {
      await ctx.reply("I’m busy summarizing another link. Please try again in a moment.");
      return;
    }

    chatLocks.add(key);
    globalInFlight += 1;

    try {
      for (const url of urls) {
        try {
          await summarizeUrl(ctx, url);
        } catch (err) {
          log.warn("[url] processing failure", {
            host: hostnameOf(url),
            error: safeErr(err)
          });
          await ctx.reply("I could not access or summarize that URL. It may be private, blocked, deleted, behind a login wall, or unsupported.");
        }
      }
    } finally {
      chatLocks.delete(key);
      globalInFlight = Math.max(0, globalInFlight - 1);
    }
  });
}

index.js.content:
import "dotenv/config";
import { run } from "@grammyjs/runner";
import { safeErr } from "./lib/errors.js";

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

let activeRunner = null;
let stopping = false;

process.on("unhandledRejection", (err) => {
  console.error("[runtime] unhandledRejection", { error: safeErr(err) });
  process.exit(1);
});

process.on("uncaughtException", (err) => {
  console.error("[runtime] uncaughtException", { error: safeErr(err) });
  process.exit(1);
});

async function importBootModule(path) {
  try {
    return await import(path);
  } catch (err) {
    console.error("[boot] module import failed", {
      path,
      code: err?.code || "UNKNOWN",
      error: safeErr(err)
    });

    if (err?.code === "ERR_MODULE_NOT_FOUND") {
      console.error("[boot] check that all relative imports include .js and referenced files exist under src");
    }

    throw err;
  }
}

async function stopRunner() {
  stopping = true;

  if (activeRunner) {
    try {
      activeRunner.stop();
      await activeRunner.task();
    } catch (err) {
      console.warn("[polling] runner stop warning", { error: safeErr(err) });
    }
  }
}

process.once("SIGINT", async () => {
  console.log("[shutdown] SIGINT received");
  await stopRunner();
  process.exit(0);
});

process.once("SIGTERM", async () => {
  console.log("[shutdown] SIGTERM received");
  await stopRunner();
  process.exit(0);
});

function startMemoryLog() {
  setInterval(() => {
    const m = process.memoryUsage();
    console.log("[mem]", {
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6)
    });
  }, 60_000).unref();
}

async function boot() {
  try {
    console.log("[boot] starting Link Brief Bot");

    const { cfg } = await importBootModule("./lib/config.js");
    const { createBot } = await importBootModule("./bot.js");
    const { registerCommands } = await importBootModule("./commands/loader.js");
    const { registerUrlSummarizer } = await importBootModule("./features/urlSummarizer.js");

    console.log("[boot] env sanity", {
      TELEGRAM_BOT_TOKEN_set: Boolean(cfg.TELEGRAM_BOT_TOKEN),
      COOKMYBOTS_AI_ENDPOINT_set: Boolean(cfg.COOKMYBOTS_AI_ENDPOINT),
      COOKMYBOTS_AI_KEY_set: Boolean(cfg.COOKMYBOTS_AI_KEY),
      COOKMYBOTS_X_ENDPOINT_set: Boolean(cfg.COOKMYBOTS_X_ENDPOINT),
      COOKMYBOTS_X_KEY_set: Boolean(cfg.COOKMYBOTS_X_KEY)
    });

    const missing = [];
    if (!cfg.TELEGRAM_BOT_TOKEN) missing.push("TELEGRAM_BOT_TOKEN");
    if (!cfg.COOKMYBOTS_AI_ENDPOINT) missing.push("COOKMYBOTS_AI_ENDPOINT");
    if (!cfg.COOKMYBOTS_AI_KEY) missing.push("COOKMYBOTS_AI_KEY");

    if (missing.length > 0) {
      console.error("[boot] missing required env vars", { missing });
      console.error("[boot] add the missing keys in your environment or .env file, then redeploy");
      process.exit(1);
    }

    const bot = createBot(cfg.TELEGRAM_BOT_TOKEN);

    bot.catch((err) => {
      console.error("[telegram] bot middleware error", {
        updateId: err.ctx?.update?.update_id,
        error: safeErr(err.error || err)
      });
    });

    await bot.init();
    await registerCommands(bot);
    registerUrlSummarizer(bot);

    try {
      await bot.api.setMyCommands([
        { command: "start", description: "How to summarize links" },
        { command: "help", description: "Supported links and failures" }
      ]);
    } catch (err) {
      console.warn("[telegram] setMyCommands failed", { error: safeErr(err) });
    }

    startMemoryLog();

    let backoffMs = 2_000;

    while (!stopping) {
      try {
        console.log("[polling] clearing webhook before long polling");
        await bot.api.deleteWebhook({ drop_pending_updates: true });

        console.log("[polling] starting runner", { concurrency: 1 });
        activeRunner = run(bot, {
          runner: {
            sink: {
              concurrency: 1
            }
          }
        });

        console.log("[polling] runner started");
        await activeRunner.task();
        console.log("[polling] runner stopped");
        break;
      } catch (err) {
        const message = safeErr(err);
        const isConflict = message.includes("409") || message.toLowerCase().includes("conflict");

        console.warn("[polling] runner failure", {
          conflict: isConflict,
          backoffMs,
          error: message
        });

        if (activeRunner) {
          try {
            activeRunner.stop();
          } catch (stopErr) {
            console.warn("[polling] runner stop after failure warning", { error: safeErr(stopErr) });
          }
          activeRunner = null;
        }

        await sleep(backoffMs);
        backoffMs = Math.min(backoffMs === 2_000 ? 5_000 : backoffMs * 2, 20_000);
      }
    }
  } catch (err) {
    console.error("[boot] fatal", { error: safeErr(err) });
    process.exit(1);
  }
}

boot();

ai.js.content:
import { cfg } from "./config.js";
import { safeErr } from "./errors.js";
import { log } from "./log.js";

function trimBaseUrl(value) {
  return String(value || "").replace(/\/+$/, "");
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function timeoutSignal(timeoutMs) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  return {
    signal: controller.signal,
    clear: () => clearTimeout(timer)
  };
}

function isRetryable(status) {
  return status === 408 || status === 429 || status === 500 || status === 502 || status === 503 || status === 504;
}

async function readJson(response) {
  const text = await response.text();
  try {
    return { text, json: JSON.parse(text) };
  } catch {
    return { text, json: null };
  }
}

export async function aiChat({ messages, meta = {}, timeoutMs = cfg.AI_TIMEOUT_MS, retries = cfg.AI_MAX_RETRIES }) {
  const base = trimBaseUrl(cfg.COOKMYBOTS_AI_ENDPOINT);
  const key = cfg.COOKMYBOTS_AI_KEY;

  if (!base || !key) {
    const error = "AI gateway is not configured";
    log.error("[ai] chat failure", { feature: "chat", configured: false, error });
    return { ok: false, error };
  }

  const safeTimeout = Number.isFinite(Number(timeoutMs)) && Number(timeoutMs) > 0 ? Number(timeoutMs) : 600000;
  const safeRetries = Number.isFinite(Number(retries)) && Number(retries) >= 0 ? Number(retries) : 2;

  let attempt = 0;
  const startedAt = Date.now();

  while (attempt <= safeRetries) {
    attempt += 1;
    const timeout = timeoutSignal(safeTimeout);

    try {
      log.info("[ai] chat start", {
        platform: "telegram",
        feature: "url_summary",
        attempt,
        timeoutMs: safeTimeout
      });

      const response = await fetch(`${base}/chat`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${key}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          messages,
          meta: {
            platform: "telegram",
            feature: "url_summary",
            ...meta
          }
        }),
        signal: timeout.signal
      });

      const { json, text } = await readJson(response);

      if (!response.ok) {
        const error = json?.error?.message || json?.message || json?.error || text || `HTTP ${response.status}`;
        log.warn("[ai] chat failure", {
          platform: "telegram",
          feature: "url_summary",
          attempt,
          status: response.status,
          error: String(error).slice(0, 500)
        });

        if (attempt <= safeRetries && isRetryable(response.status)) {
          await sleep(750 * attempt);
          continue;
        }

        return { ok: false, error: String(error), status: response.status };
      }

      const content = json?.output?.content;

      if (typeof content !== "string" || !content.trim()) {
        const error = "AI gateway returned no chat content";
        log.warn("[ai] chat failure", {
          platform: "telegram",
          feature: "url_summary",
          attempt,
          status: response.status,
          error
        });
        return { ok: false, error, status: response.status };
      }

      log.info("[ai] chat success", {
        platform: "telegram",
        feature: "url_summary",
        attempt,
        status: response.status,
        ms: Date.now() - startedAt
      });

      return {
        ok: true,
        content: content.trim(),
        id: json?.id || "",
        usage: json?.usage || null
      };
    } catch (err) {
      const error = err?.name === "AbortError" ? "AI request timed out" : safeErr(err);
      log.warn("[ai] chat failure", {
        platform: "telegram",
        feature: "url_summary",
        attempt,
        error
      });

      if (attempt <= safeRetries) {
        await sleep(750 * attempt);
        continue;
      }

      return { ok: false, error };
    } finally {
      timeout.clear();
    }
  }

  return { ok: false, error: "AI request failed" };
}

