summarizer.js.content:
import { aiChat } from "../lib/ai.js";
import { buildBotProfile } from "../lib/botProfile.js";

function normalizeWhitespace(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function splitSentences(value) {
  const text = normalizeWhitespace(value);
  const matches = text.match(/[^.!?]+[.!?]+(?:["')\]]+)?/g);
  if (matches?.length) return matches.map((sentence) => normalizeWhitespace(sentence)).filter(Boolean);
  return text ? [text.endsWith(".") ? text : `${text}.`] : [];
}

function exactThreeSentences(value) {
  const sentences = splitSentences(value).slice(0, 3);

  while (sentences.length < 3) {
    sentences.push("The source does not provide enough additional accessible detail for a fuller summary.");
  }

  return sentences.join(" ");
}

export async function summarizeDocument(document) {
  const sourceText = normalizeWhitespace(document.text).slice(0, 12_000);
  const title = normalizeWhitespace(document.title || "Untitled source").slice(0, 300);

  const messages = [
    {
      role: "system",
      content: buildBotProfile()
    },
    {
      role: "system",
      content: "Summarize the provided source in exactly 3 complete sentences. Use only information supported by the source text. Do not use bullets, headings, markdown, citations, or extra commentary."
    },
    {
      role: "user",
      content: `Source type: ${document.sourceType}\nTitle: ${title}\nURL: ${document.url}\nContent:\n${sourceText}`
    }
  ];

  const result = await aiChat({
    messages,
    meta: {
      sourceType: document.sourceType,
      host: (() => {
        try {
          return new URL(document.url).hostname;
        } catch {
          return "unknown";
        }
      })()
    }
  });

  if (!result.ok) {
    return result;
  }

  return {
    ok: true,
    content: exactThreeSentences(result.content)
  };
}

urlTools.js.content:
const URL_RE = /(https?:\/\/[^\s<>"]+|www\.[^\s<>"]+)/gi;

function trimTrailingPunctuation(value) {
  return String(value || "").replace(/[),.;!?]+$/g, "");
}

export function extractUrls(text) {
  const found = [];
  const seen = new Set();
  const matches = String(text || "").matchAll(URL_RE);

  for (const match of matches) {
    const raw = trimTrailingPunctuation(match[0]);
    const withScheme = raw.toLowerCase().startsWith("www.") ? `https://${raw}` : raw;

    try {
      const parsed = new URL(withScheme);
      if (parsed.protocol !== "http:" && parsed.protocol !== "https:") continue;

      parsed.hash = "";
      const normalized = parsed.toString();

      if (!seen.has(normalized)) {
        seen.add(normalized);
        found.push(normalized);
      }
    } catch {
      continue;
    }
  }

  return found.slice(0, 3);
}

export function isXUrl(url) {
  try {
    const host = new URL(url).hostname.toLowerCase().replace(/^www\./, "");
    return host === "x.com" || host === "twitter.com" || host === "mobile.twitter.com";
  } catch {
    return false;
  }
}

export function extractTweetId(url) {
  try {
    const parsed = new URL(url);
    const match = parsed.pathname.match(/\/status(?:es)?\/(\d+)/i);
    return match ? match[1] : "";
  } catch {
    return "";
  }
}

export function hostnameOf(url) {
  try {
    return new URL(url).hostname.toLowerCase();
  } catch {
    return "unknown";
  }
}

webPage.js.content:
const log = {
  info:  (...a) => console.log(...a),
  warn:  (...a) => console.warn(...a),
  error: (...a) => console.error(...a),
};

import dns from "node:dns/promises";
import * as cheerio from "cheerio";
import { safeErr } from "../lib/errors.js";

const MAX_BYTES = 1_500_000;
const MAX_TEXT_CHARS = 12_000;
const FETCH_TIMEOUT_MS = 25_000;
const MAX_REDIRECTS = 5;
const USER_AGENT = "LinkBriefBot/1.0 (+https://cookmybots.com; Telegram URL summarizer)";

function withTimeout(ms) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  return {
    signal: controller.signal,
    clear: () => clearTimeout(timer)
  };
}

function isPrivateIPv4(address) {
  const parts = address.split(".").map((part) => Number(part));
  if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) return true;

  const [a, b] = parts;
  return (
    a === 10 ||
    a === 127 ||
    (a === 169 && b === 254) ||
    (a === 172 && b >= 16 && b <= 31) ||
    (a === 192 && b === 168) ||
    a === 0
  );
}

function isPrivateIPv6(address) {
  const value = address.toLowerCase();
  return value === "::1" || value.startsWith("fc") || value.startsWith("fd") || value.startsWith("fe80") || value === "::";
}

async function assertSafeUrl(url) {
  const parsed = new URL(url);

  if (parsed.protocol !== "http:" && parsed.protocol !== "https:") {
    throw new Error("Unsupported URL scheme");
  }

  const hostname = parsed.hostname.toLowerCase();
  if (hostname === "localhost" || hostname.endsWith(".localhost")) {
    throw new Error("Local URLs are not supported");
  }

  const records = await dns.lookup(hostname, { all: true, verbatim: false });
  if (!records.length) {
    throw new Error("Could not resolve hostname");
  }

  for (const record of records) {
    if (record.family === 4 && isPrivateIPv4(record.address)) {
      throw new Error("Private network URLs are not supported");
    }
    if (record.family === 6 && isPrivateIPv6(record.address)) {
      throw new Error("Private network URLs are not supported");
    }
  }
}

function ensureTextContent(contentType) {
  const type = String(contentType || "").toLowerCase();
  if (!type) return;

  const ok =
    type.includes("text/html") ||
    type.includes("application/xhtml+xml") ||
    type.includes("text/plain");

  if (!ok) {
    throw new Error("Unsupported content type");
  }
}

export async function fetchPageHtml(url) {
  let currentUrl = url;

  for (let redirect = 0; redirect <= MAX_REDIRECTS; redirect += 1) {
    await assertSafeUrl(currentUrl);
    const timeout = withTimeout(FETCH_TIMEOUT_MS);

    try {
      log.info("[fetch] page start", { host: new URL(currentUrl).hostname, redirect });

      const response = await fetch(currentUrl, {
        method: "GET",
        redirect: "manual",
        headers: {
          "User-Agent": USER_AGENT,
          Accept: "text/html,application/xhtml+xml,text/plain;q=0.9,*/*;q=0.1"
        },
        signal: timeout.signal
      });

      if ([301, 302, 303, 307, 308].includes(response.status)) {
        const location = response.headers.get("location");
        if (!location) throw new Error("Redirect missing location");
        currentUrl = new URL(location, currentUrl).toString();
        continue;
      }

      if (!response.ok) {
        throw new Error(`Fetch failed with HTTP ${response.status}`);
      }

      const contentType = response.headers.get("content-type") || "";
      ensureTextContent(contentType);

      const length = Number(response.headers.get("content-length") || 0);
      if (Number.isFinite(length) && length > MAX_BYTES) {
        throw new Error("Page is too large to summarize safely");
      }

      const arrayBuffer = await response.arrayBuffer();
      if (arrayBuffer.byteLength > MAX_BYTES) {
        throw new Error("Page is too large to summarize safely");
      }

      const html = Buffer.from(arrayBuffer).toString("utf8");
      log.info("[fetch] page success", {
        host: new URL(currentUrl).hostname,
        bytes: arrayBuffer.byteLength,
        contentType: contentType.slice(0, 80)
      });

      return {
        finalUrl: currentUrl,
        contentType,
        html
      };
    } catch (err) {
      log.warn("[fetch] page failure", {
        host: (() => {
          try {
            return new URL(currentUrl).hostname;
          } catch {
            return "unknown";
          }
        })(),
        error: safeErr(err)
      });
      throw err;
    } finally {
      timeout.clear();
    }
  }

  throw new Error("Too many redirects");
}

function normalizeWhitespace(value) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .replace(/\u00a0/g, " ")
    .trim();
}

export function extractReadableText({ html, finalUrl }) {
  const $ = cheerio.load(html || "");

  $("script, style, noscript, svg, canvas, iframe, nav, footer, header, aside, form, button, input, select, textarea").remove();
  $("[aria-hidden='true'], [hidden]").remove();

  const title = normalizeWhitespace($("meta[property='og:title']").attr("content") || $("title").first().text() || "");
  const description = normalizeWhitespace(
    $("meta[name='description']").attr("content") || $("meta[property='og:description']").attr("content") || ""
  );

  const candidates = [
    "article",
    "main",
    "[role='main']",
    ".article",
    ".post",
    ".entry-content",
    ".content",
    "body"
  ];

  let bestText = "";

  for (const selector of candidates) {
    const node = $(selector).first();
    if (!node.length) continue;

    const parts = [];
    node.find("h1,h2,h3,p,li,blockquote,pre").each((_, element) => {
      const text = normalizeWhitespace($(element).text());
      if (text.length >= 20) parts.push(text);
    });

    const candidate = normalizeWhitespace(parts.join("\n"));
    if (candidate.length > bestText.length) bestText = candidate;
  }

  let text = bestText || normalizeWhitespace($("body").text());
  if (description && !text.includes(description)) {
    text = normalizeWhitespace(`${description}\n${text}`);
  }

  text = text.slice(0, MAX_TEXT_CHARS);

  if (text.length < 80) {
    throw new Error("Not enough readable text found");
  }

  return {
    sourceType: "webpage",
    title: title || new URL(finalUrl).hostname,
    url: finalUrl,
    text
  };
}

xGateway.js.content:
const log = {
  info:  (...a) => console.log(...a),
  warn:  (...a) => console.warn(...a),
  error: (...a) => console.error(...a),
};

import { cfg } from "../lib/config.js";
import { safeErr } from "../lib/errors.js";

import { extractTweetId } from "./urlTools.js";

function trimBaseUrl(value) {
  return String(value || "").replace(/\/+$/, "");
}

function timeoutSignal(ms) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  return {
    signal: controller.signal,
    clear: () => clearTimeout(timer)
  };
}

async function xProxy({ path, method = "GET", query, body }) {
  const base = trimBaseUrl(cfg.COOKMYBOTS_X_ENDPOINT);
  const key = cfg.COOKMYBOTS_X_KEY;

  if (!base || !key) {
    return {
      ok: false,
      status: 412,
      error: "X/Twitter summarization is not configured"
    };
  }

  const timeout = timeoutSignal(30_000);

  try {
    const response = await fetch(`${base}/proxy`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${key}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ path, method, query, body }),
      signal: timeout.signal
    });

    const text = await response.text();
    let json = null;
    try {
      json = JSON.parse(text);
    } catch {
      json = null;
    }

    if (!response.ok) {
      const error = json?.error?.message || json?.message || json?.error || text || `HTTP ${response.status}`;
      return { ok: false, status: response.status, error: String(error), json };
    }

    return { ok: true, status: response.status, json };
  } catch (err) {
    return { ok: false, status: err?.name === "AbortError" ? 408 : 0, error: safeErr(err), json: null };
  } finally {
    timeout.clear();
  }
}

function tweetData(json) {
  return json?.data || json?.result?.data || json?.response?.data || null;
}

function includesData(json) {
  return json?.includes || json?.result?.includes || json?.response?.includes || {};
}

function formatTweet(tweet, usersById = new Map()) {
  if (!tweet?.text) return "";
  const author = usersById.get(tweet.author_id);
  const name = author?.username ? `@${author.username}` : "tweet";
  return `${name}: ${tweet.text}`;
}

export async function fetchXContent(url) {
  const tweetId = extractTweetId(url);

  if (!tweetId) {
    return {
      ok: false,
      configured: Boolean(cfg.COOKMYBOTS_X_ENDPOINT && cfg.COOKMYBOTS_X_KEY),
      error: "No tweet status ID found"
    };
  }

  if (!cfg.COOKMYBOTS_X_ENDPOINT || !cfg.COOKMYBOTS_X_KEY) {
    log.warn("[x] content fetch failure", { configured: false, reason: "missing_x_gateway_env" });
    return {
      ok: false,
      configured: false,
      error: "X/Twitter summarization is not configured"
    };
  }

  log.info("[x] content fetch start", { tweetId });

  const single = await xProxy({
    path: `/2/tweets/${tweetId}`,
    method: "GET",
    query: {
      "tweet.fields": "author_id,conversation_id,created_at,text",
      expansions: "author_id",
      "user.fields": "username,name"
    }
  });

  if (!single.ok) {
    log.warn("[x] content fetch failure", { tweetId, status: single.status, error: String(single.error || "").slice(0, 300) });
    return {
      ok: false,
      configured: true,
      error: "The tweet or thread may be private, deleted, rate-limited, or inaccessible"
    };
  }

  const tweet = tweetData(single.json);
  if (!tweet?.text) {
    log.warn("[x] content fetch failure", { tweetId, status: single.status, error: "missing_tweet_text" });
    return {
      ok: false,
      configured: true,
      error: "The tweet or thread may be private, deleted, rate-limited, or inaccessible"
    };
  }

  const users = includesData(single.json)?.users || [];
  const usersById = new Map(users.map((user) => [user.id, user]));
  const lines = [formatTweet(tweet, usersById)];

  if (tweet.conversation_id && tweet.author_id) {
    const thread = await xProxy({
      path: "/2/tweets/search/recent",
      method: "GET",
      query: {
        query: `conversation_id:${tweet.conversation_id} from:${tweet.author_id} -is:retweet`,
        max_results: "10",
        "tweet.fields": "author_id,created_at,text",
        expansions: "author_id",
        "user.fields": "username,name"
      }
    });

    if (thread.ok) {
      const threadTweets = Array.isArray(tweetData(thread.json)) ? tweetData(thread.json) : [];
      const threadUsers = includesData(thread.json)?.users || [];
      const threadUsersById = new Map([...usersById, ...threadUsers.map((user) => [user.id, user])]);

      const sorted = threadTweets
        .filter((item) => item?.id && item?.text)
        .sort((a, b) => String(a.created_at || "").localeCompare(String(b.created_at || "")));

      for (const item of sorted) {
        const line = formatTweet(item, threadUsersById);
        if (line && !lines.includes(line)) lines.push(line);
      }
    } else {
      log.warn("[x] thread fetch fallback", { tweetId, status: thread.status, error: String(thread.error || "").slice(0, 300) });
    }
  }

  const text = lines.join("\n").trim();

  log.info("[x] content fetch success", { tweetId, chars: text.length, lines: lines.length });

  return {
    ok: true,
    configured: true,
    document: {
      sourceType: "x_twitter",
      title: "X/Twitter post",
      url,
      text: text.slice(0, 12_000)
    }
  };
}
